def max_sum(triangle):
    max_sum = [0] * len(triangle)
    for i in range(len(triangle)):
        current_row = triangle[i]
        max_sum[i] = current_row[0]
        for j in range(1, len(current_row)):
            max_sum[i] = max(max_sum[i-1], max_sum[i-2] + current_row[j])
    return max(max_sum)

# Test cases
assert max_sum([[1], [2,1], [3,3,2]]) == 6
assert max_sum([[1], [1, 2], [4, 1, 12]]) == 15
assert max_sum([[2], [3,2], [13,23,12]]) == 28

def max_sum(triangle):
    n = len(triangle)
    max_sum = [row[:] for row in triangle]
    for i in range(1, n):
        for j in range(len(max_sum[i])):
            current_max = max(max_sum[i-1][j], max_sum[i-1][j-1]) + triangle[i][j]
            max_sum[i][j] = current_max
    return max(max_sum[-1])

# Test cases
assert max_sum([[1], [2,1], [3,3,2]]) == 6
assert max_sum([[1], [1, 2], [4, 1, 12]]) == 15
assert max_sum([[2], [3,2], [13,23,12]]) == 28
